import { useEffect, useRef, useState } from "react";

const LIMIT = 10;

export default function useData(page) {
    const [data, setData] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);

    // ✅ cache to prevent duplicate calls (key = page)
    const fetchedPages = useRef(new Set());

    useEffect(() => {
        // 🚫 prevent duplicate fetch for same page (StrictMode fix)
        if (fetchedPages.current.has(page)) return;

        fetchedPages.current.add(page);

        const controller = new AbortController();

        async function fetchData() {
            try {
                setLoading(true);

                const skip = page * LIMIT;

                const res = await fetch(
                    `https://dummyjson.com/products?limit=${LIMIT}&skip=${skip}`,
                    { signal: controller.signal }
                );

                const json = await res.json();

                setData(json.products);
            } catch (err) {
                if (err.name !== "AbortError") {
                    setError(err);
                }
            } finally {
                setLoading(false);
            }
        }

        fetchData();

        // ✅ cleanup for strict mode + fast refresh
        return () => {
            controller.abort();
        };
    }, [page]);

    return {
        tableData: data,
        loading,
        error,
        total: 100 // or return from API if available
    };
}
